import React from 'react';
import './Products.css';
import shirt1 from '../assets/shirt1.webp';
import shirt2 from '../assets/shirt2.jpg';
import shirt3 from '../assets/shirt3.jpg';
import shirt4 from '../assets/shirt4.webp';
import pant1 from '../assets/pant1.jpg';
import pant2 from '../assets/pant1.jpg';
import pant3 from '../assets/pant1.jpg';

function Products() {
  // 👕 Shirt collection
  const shirts = [
    {
      id: 1,
      name: "Casual Shirt",
      price: "₹799",
      image: shirt1,
      whatsappMessage: "Hi, I'm interested in buying the Casual Shirt for ₹799"
    },
    {
      id: 2,
      name: "Formal Shirt",
      price: "₹999",
      image: shirt2,
      whatsappMessage: "Hi, I'm interested in buying the Formal Shirt for ₹999"
    },
    {
      id: 3,
      name: "Formal Shirt",
      price: "₹999",
      image: shirt3,
      whatsappMessage: "Hi, I would like to buy the Formal Shirt for ₹999"
    },
    {
      id: 4,
      name: "Formal Shirt",
      price: "₹999",
      image: shirt4,
      whatsappMessage: "Hello! I'm interested in the Formal Shirt (₹999)"
    }
  ];

  // 👖 Pant collection
  const pants = [
    {
      id: 1,
      name: "Denim Jeans",
      price: "₹1199",
      image: pant1,
      whatsappMessage: "Hi, I want to buy the Denim Jeans for ₹1199"
    },
    {
      id: 2,
      name: "Cotton Chinos",
      price: "₹899",
      image: pant2,
      whatsappMessage: "Hi, I'm interested in Cotton Chinos for ₹899"
    },
    {
      id: 3,
      name: "Cotton Chinos",
      price: "₹899",
      image: pant3,
      whatsappMessage: "Hi, I want to buy the Cotton Chinos for ₹899"
    }
  ];

  return (
    <div className="products-container">
      <h1 className="section-title">👕 Shirts Collection</h1>
      <div className="product-grid">
        {shirts.map((item) => (
          <div key={item.id} className="product-card">
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p>{item.price}</p>
            <a
              href={`https://wa.me/916379112645?text=${encodeURIComponent(item.whatsappMessage)}`}
              target="_blank"
              rel="noopener noreferrer"
              className="buy-btn"
            >
              🛒 Buy Now
            </a>
          </div>
        ))}
      </div>

      <h1 className="section-title">👖 Pants Collection</h1>
      <div className="product-grid">
        {pants.map((item) => (
          <div key={item.id} className="product-card">
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p>{item.price}</p>
            <a
              href={`https://wa.me/919876543210?text=${encodeURIComponent(item.whatsappMessage)}`}
              target="_blank"
              rel="noopener noreferrer"
              className="buy-btn"
            >
              🛒 Buy Now
            </a>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Products;
